    problema: { title: "Being reactive costs clients and margin", p: "SAP integrations break silently and the client finds out before you do. The team firefights, with no single view, and proving the value delivered is hard. SAPLINK flips the game.", cards: [["Before", "Stuck IDoc, RFC down, e-invoice halted — found out too late."], ["Without SAPLINK", "Spreadsheets, transaction by transaction, client by client. Doesn't scale."], ["With SAPLINK", "One radar, alerts, AI and value proof in $. You're in control."]], beforeTag: "BEFORE · reactive", beforeText: "Spreadsheets, transaction by transaction, client by client. Stuck IDoc found late. Client calls before you notice.", beforeChips: ["no single view", "firefighting", "invisible value"], afterTag: "AFTER · with SAPLINK", afterText: "One portfolio radar · prioritized alerts · AI diagnoses and fixes · $ at risk live · SLA per client.", afterChips: ["health 92", "0 open ports", "−70% downtime", "proof in $"], drag: "← drag to compare →" },
    como: { title: "How it works", sub: "From the client's SAP to action — data flows outbound only, no open ports.", flow: [["🗄️", "Client's SAP", "S/4 · ECC · CPI"], ["🔌", "Agent / Connector", "outbound-only · OData"], ["◆", "SAPLINK", "AI · multi-client"], ["✅", "Action & value", "alert · fix · $"]], steps: [["1", "Connect", "Docker Agent (RFC/IDoc) with outbound HTTPS only, or Communication Arrangement on S/4HANA Cloud. Zero open ports."], ["2", "See", "Health of every integration across every client in one multi-client dashboard, in real time."], ["3", "Anticipate & fix", "AI diagnoses, predicts failures and remediates (with approval) — IDoc, queue, RFC, tax."], ["4", "Prove value", "SLA per client, impact in $ and a white-label portal. You become the client's SAP radar."]] },
